//function-utils.js
import { getPropVal } from './zcutils';

/**
 *
 * @param {Function|*}object
 * @returns {boolean}
 */
function isFunction(object) {
    return !!(object && object.constructor && object.call && object.apply);
}

/**
 * @param  {Function} main [description]
 * @param  {Function} sub  function1, function2, function3...
 * @return {Function}      [description]
 */
function extendFunction(main, ...sub) {
    return function() {
        var self = this,
            arg = arguments;

        main.apply(self, arg);
        sub.forEach(func => func.apply(self, arg));
    };
}

function supportedFunction(name) {
    return isFunction(name) || (typeof name === 'string' && isFunction(getPropVal(window, name)));
}

export { isFunction, extendFunction, supportedFunction };
